# checkers/checkers.py

class CheckersGame:
    def __init__(self):
        self.board = [
            [None, 'b', None, 'b', None, 'b', None, 'b'],
            ['b', None, 'b', None, 'b', None, 'b', None],
            [None, None, None, None, None, None, None, None],
            [None, 'w', None, 'w', None, 'w', None, 'w'],
            [None, None, None, None, None, None, None, None],
            ['w', None, 'w', None, 'w', None, 'w', None],
            [None, 'b', None, 'b', None, 'b', None, 'b'],
            ['b', None, 'b', None, 'b', None, 'b', None]
        ]
        self.turn = 'b'

    def print_board(self):
        for row in self.board:
            print(' '.join([f"{cell:2}" if cell else '__' for cell in row]))

    def get_piece(self, x, y):
        return self.board[y][x]

    def is_valid_move(self, start_x, start_y, end_x, end_y):
        piece = self.get_piece(start_x, start_y)
        if not piece:
            return False
        if piece[0] != self.turn:
            return False
        if abs(end_x - start_x) not in [1, 2]:
            return False
        if abs(end_y - start_y) != 1:
            return False
        # Simple move or jump validation
        if abs(end_x - start_x) == 1 and self.get_piece(end_x, end_y):
            return False
        if abs(end_x - start_x) == 2:
            mid_x = (start_x + end_x) // 2
            mid_y = (start_y + end_y) // 2
            if not self.get_piece(mid_x, mid_y) or self.get_piece(mid_x, mid_y)[0] == piece[0]:
                return False
        return True

    def make_move(self, start_x, start_y, end_x, end_y):
        if not self.is_valid_move(start_x, start_y, end_x, end_y):
            raise ValueError("Invalid move")
        piece = self.get_piece(start_x, start_y)
        self.board[start_y][start_x] = None
        self.board[end_y][end_x] = piece
        if abs(end_x - start_x) == 2:
            mid_x = (start_x + end_x) // 2
            mid_y = (start_y + end_y) // 2
            self.board[mid_y][mid_x] = None

    def switch_turn(self):
        self.turn = 'w' if self.turn == 'b' else 'b'

    def check_winner(self):
        # Simplified win condition for demonstration
        pieces_count = sum(row.count('b') + row.count('w') for row in self.board)
        if pieces_count == 1:
            return self.turn.upper()
        return None

    def play_game(self):
        while True:
            self.print_board()
            start_x, start_y = map(int, input(f"Player {self.turn}, enter your move (e.g., 0 0 to 2 2): ").split())
            end_x, end_y = map(int, input("Enter destination: ").split())
            try:
                self.make_move(start_x, start_y, end_x, end_y)
                if winner := self.check_winner():
                    print(f"Player {winner} wins!")
                    break
                self.switch_turn()
            except ValueError as e:
                print(e)
